// ── Pi-CEO Morning Intel Formatter (RA-845) ──────────────────────────────
// Extracts relevant content from fetched pages and formats for board meeting injection.

const today = new Date().toISOString().split('T')[0];

const anthropicRaw = $('Fetch Anthropic News').first().json.data || '';
const openaiRaw    = $('Fetch OpenAI News').first().json.data || '';
const xaiRaw       = $('Fetch xAI Blog').first().json.data || '';

// Keywords that indicate material changes worth flagging
const CRITICAL_KEYWORDS = ['agent sdk', 'mcp', 'model context protocol', 'breaking', 'deprecat', 'hook', 'subagent'];
const COST_KEYWORDS     = ['price', 'pricing', 'cost reduction', 'context window', 'tokens', 'rate limit'];
const ADOPT_KEYWORDS    = ['new feature', 'now available', 'launch', 'release', 'introduce', 'api update', 'beta', 'ga ', 'generally available'];

function extractText(html) {
  // Strip HTML tags and collapse whitespace
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 3000);
}

function detectFlags(text, platform) {
  const lower = text.toLowerCase();
  const flags = [];
  for (const kw of CRITICAL_KEYWORDS) {
    if (lower.includes(kw)) {
      flags.push(`🔴 CRITICAL [${platform}]: mentions "${kw}" — verify impact on Agent SDK / MCP pipeline`);
      break;
    }
  }
  for (const kw of COST_KEYWORDS) {
    if (lower.includes(kw)) {
      flags.push(`🟡 COST/CAPACITY [${platform}]: mentions "${kw}" — check for pricing or capacity changes`);
      break;
    }
  }
  for (const kw of ADOPT_KEYWORDS) {
    if (lower.includes(kw)) {
      flags.push(`🟢 ADOPT [${platform}]: new release/feature detected — evaluate for portfolio integration`);
      break;
    }
  }
  return flags;
}

const anthropicText = extractText(anthropicRaw);
const openaiText    = extractText(openaiRaw);
const xaiText       = extractText(xaiRaw);

const allFlags = [
  ...detectFlags(anthropicText, 'Anthropic'),
  ...detectFlags(openaiText, 'OpenAI'),
  ...detectFlags(xaiText, 'xAI'),
];

const payload = {
  date: today,
  anthropic: anthropicText.slice(0, 800),
  openai: openaiText.slice(0, 800),
  xai: xaiText.slice(0, 800),
  flags: allFlags,
  source: 'n8n:morning-intel',
  generated_at: new Date().toISOString(),
};

return [{ json: payload }];

const res = $input.first().json;
const ok = res.ok === true;
const critical = res.critical || 0;
const flags = res.flags || 0;

if (!ok) {
  throw new Error(`Pi-CEO morning intel POST failed: ${JSON.stringify(res)}`);
}

console.log(`✅ Morning intel stored | date=${res.date} | flags=${flags} | critical=${critical}`);

if (critical > 0) {
  console.warn(`🔴 ${critical} CRITICAL flag(s) detected — board meeting will surface these in Phase 1`);
}

return [{ json: { success: true, date: res.date, flags, critical } }];
